                </button>
              </div>
              <div class="modal-body">
                <dynamic-form ref="dynamicform" lang="en" :mandatorytext="$t('MandatoryString')" :buttons="commentButtons" v-on:OnSubmit="OnSubmit" :schema="FormSchema"> </dynamic-form>
              </div>
              <!-- <div class="row flex-row-reverse mt-3 mb-3">
                <div class="col-lg-6 text-right">
