  <script>
  import DataService from '../../services/DataService';
  
  export default {
    props: {
      ProjectName: {
        type: String,
        required: true
      }
    },
    data() {
      return {
        noRecord: false,
        TotalRecords: 0,
        isLoading: false,
        taskOptions: [],
