          {
            layoutType: "triple",
            Data: [
              {
                astype: "TextField",
                label: this.$t('Category'),
                name: "MilestoneName",
                value: "",
                placeholder: "",
                validationRules: {
                  "required": true,
                  "regex": /^[a-zA-Z0-9\s]*$/
                },
                disabled: false
              },
              {
                astype: "SelectField",
                label: this.$t('Type'),
                name: "MilestoneName",
                value: "",
                placeholder: "",
                config: {
                options: [
                    { value: 'EXPENSE_CATEGORY', name: 'Expense' },  
                   ]},    
                     validationRules: {
                  "required": true,               
                },
                disabled: false
              },
              {
                astype: "SelectField",
                label: this.$t('Status'),
                name: "Status",
                value: "",
                placeholder: "",
                validationRules: {
                    required: true,
                },
                config: { options: [] },
                disabled: false,
            },
            ]
          },
          {
           layoutType: "single",
            Data: [
              {
                astype: "TextAreaField",
                label: this.$t('Description'),
                name: "Description",
                value: "",
                config: {
                  rows: 3
                },
                placeholder: this.$t(''),
                validationRules: {
                  "required": true,
                  max: 2000,
                  "regex": /^[a-zA-Z0-9\s]*$/
                }
              }
            ]
          }
          
        ],
        commentButtons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                    //onClick:this.SaveCategory
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Cancel,
                },
            ] 
          };
    },
    created() {
      var vm = this;
      vm.projectId = vm.$route.params.projectId;
      vm.GetStatus();  
   
    },
    methods: {       
      OnSubmit() {
          debugger
            var vm = this;            
            var objData = 
            {
                projectId:vm.projectId,
                CategoryName: vm.FormSchema[0].Data[0].value,
                CategoryTypeId: vm.FormSchema[0].Data[1].value,
                StatusId: vm.FormSchema[0].Data[2].value,
                CategoryDescription: vm.FormSchema[1].Data[0].value                 
            };
            var objectPostString = JSON.stringify(objData);
            DataService.SaveCategory(objectPostString).then(function (response) {
                if (response.data.status== "Success") {                   
                    vm.ShowAlert(vm.$t('AddedSuccess',[vm.$t('Expense')]), "success", true,  vm.$t("Alert"));
                    //vm.$parent.GetAllCategoriesByCompanyId();
                    vm.Cancel();                    
                }
                else {
                    vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                }
            }); 
        }, 
        GetStatus:function(){   
            var vm= this;
            var url=`langCode=en&companyId=${vm.companyId}&statusType=Category&hasGlobal=true`
            DataService.StatusListing(url).then(response => {
                if (response.status == 200) {
                    if (response.data.result.data != undefined || response.data.result.data != null) {
                        if (response.data.result.data.length > 0) {
                            response.data.result.data.forEach((element) => {
                                var obj = {
                                    value: element.STATUS_ID,
                                    name: element.STATUS

                                }
                                vm.FormSchema[0].Data[2].config.options.push(obj);
                                 vm.$refs.dynamicform.UpdateKeyValue();
                            
                            })
                    }
                    }
                }
            })
        }, 
